class Solution {
public:
    void moveZeroes(vector<int>& nums) {
        int j=-1;
        int n=nums.size();

        for(int i=0;i<n;i++){
            if(nums[i]==0){
                j=i;
                break;
            }
        }
        if(j==-1) return;

        for(int i=j+1;i<n;i++){
            if(nums[i]!=0){
                swap(nums[i],nums[j]);
                j++;
            }
        }

    }
};

union-of-two-sorted-arrays.code:
class Solution {
public:
    vector<int> unionArray(vector<int>& nums1, vector<int>& nums2) {
        int n1=nums1.size();
        int n2=nums2.size();
        int i=0,j=0;
        vector<int>ans;

        while(i<n1 && j<n2){
            if(nums1[i]<=nums2[j]){
                if(ans.size()==0 || ans.back() != nums1[i]){
                    ans.push_back(nums1[i]);
                }
                i++;
            }
            else{
                if(ans.size()==0 || ans.back() != nums2[j]){
                    ans.push_back(nums2[j]);
                }
                j++;
            }
        }

        while(i<n1){
            if(ans.size()==0 || ans.back() != nums1[i]){
                    ans.push_back(nums1[i]);
                }
                i++;
        }

        while(j<n2){
            if(ans.size()==0 || ans.back() != nums2[j]){
                    ans.push_back(nums2[j]);
                }
                j++;
        }
        return ans;
    }
};

