    int longestConsecutive(vector<int>& nums) {
        unordered_set<int>st(nums.begin(),nums.end());
        int n=nums.size();
        long long int ans=1;
        long long int y=0,c=0;
        if(nums.size()==0) return 0;

        for(auto it:st){
            if(!st.count(it-1)){
                y=1;
                c=it;
