class Solution{
public:
    int subarraysWithXorK(vector<int> &nums, int k) {
        unordered_map<int,int> cnt;
        int xr = 0;
        long long ans = 0;
        cnt[0] = 1;
        for (int x : nums) {
            xr ^= x;
            int need = xr ^ k;
            auto it = cnt.find(need);
            if (it != cnt.end()) ans += it->second;
            cnt[xr]++;
        }
        return (int)ans;
    }
};

