vector<int> findTwoElement(vector<int> arr, int N) {
    long long n = N;
    long long optSum = n * (n + 1) / 2; 
    long long opt2Sum = n * (n + 1) * (2 * n + 1) / 6; 
    long long actSum = 0; 
    long long act2Sum = 0; 

    for (auto it : arr) {
        actSum += it;
        act2Sum += (long long)it * (long long)it;
    }

    long long xMinusY = optSum - actSum;
    long long x2MinusY2 = opt2Sum - act2Sum;
    long long xPlusY = x2MinusY2 / xMinusY;

    long long x = (xPlusY + xMinusY) / 2;
    long long y = xPlusY - x;

    return {(int)y, (int)x};
}

merge-sorting.code:
class Solution {
public:
    void merge(vector<int>& nums, int low, int mid, int high) {
        vector<int> temp;
        int left = low, right = mid + 1;
        while (left <= mid && right <= high) {
            if (nums[left] <= nums[right]) temp.push_back(nums[left++]);
            else temp.push_back(nums[right++]);
        }
        while (left <= mid) temp.push_back(nums[left++]);
        while (right <= high) temp.push_back(nums[right++]);
        for (int i = low; i <= high; i++) nums[i] = temp[i - low];
    }
    void ms(vector<int>& nums, int low, int high) {
        if (low >= high) return;
        int mid = (low + high) / 2;
        ms(nums, low, mid);
        ms(nums, mid + 1, high);
        merge(nums, low, mid, high);
    }
    vector<int> mergeSort(vector<int>& nums) {
        ms(nums, 0, (int)nums.size() - 1);
        return nums;
    }
};

reverse-pairs.code:
int rev_pair = 0;

void merge(int start, int mid, int end, vector<int>& nums){
    int left_size = mid - start + 1;
    int right_size = end - mid;
    vector<int> left(left_size);
    vector<int> right(right_size);

    for(int i = 0; i < left_size; i++){
        left[i] = nums[start + i];
    }
    for(int i = 0; i < right_size; i++){
        right[i] = nums[mid + 1 + i];
    }


    int m = 0;
    for(int i = 0; i < left_size; i++){
        while(m < right_size && left[i] > (long long)2 * right[m]){
            m++;
        }
        rev_pair += m;
    }

    int i = 0, j = 0, k = start;
    while(i < left_size && j < right_size){
        if(left[i] > right[j]){
            nums[k++] = right[j++];
        }
        else{
            nums[k++] = left[i++];
        }
    }
    while(i < left_size){
        nums[k++] = left[i++];
    }
    while(j < right_size){
        nums[k++] = right[j++];
    }
}

void mergesort(int start, int end, vector<int>& nums){
    if(start >= end)
        return;
    int mid = start + (end - start) / 2;
    mergesort(start, mid, nums);
    mergesort(mid + 1, end, nums);
    merge(start, mid, end, nums);
}

int reversePairs(vector<int>& nums) {
    rev_pair = 0;
    mergesort(0, nums.size() - 1, nums);
    return rev_pair;
}

