class Solution {
public:
    double median(vector<int> &arr1, vector<int> &arr2) {

        int n = (int)arr1.size();
        int m = (int)arr2.size();
        int total = n + m;
        int idx2 = total / 2;        
        int idx1 = (total - 1) / 2;  
        int i = 0, j = 0, cnt = 0;
        long long e1 = 0, e2 = 0;
        while (i < n || j < m) {
            int cur;
            if (j >= m || (i < n && arr1[i] <= arr2[j])) {
                cur = arr1[i++];
            } else {
                cur = arr2[j++];
            }
            if (cnt == idx1) e1 = cur;
            if (cnt == idx2) { e2 = cur; break; }
            cnt++;
        }
        return (e1 + e2) / 2.0;
    }
};

