class Solution {
public:
    int shipWithinDays(vector<int>& weights, int days) {
        long long lo = 0, hi = 0;
        for (int w : weights) {
            lo = max(lo, (long long)w); 
            hi += w;                    
        }
        auto daysNeeded = [&](long long cap) -> long long {
            long long d = 1, cur = 0;
            for (int w : weights) {
                if (cur + w > cap) { d++; cur = w; }
                else cur += w;
            }
            return d;
        };
        long long ans = hi;
        while (lo <= hi) {
            long long mid = lo + (hi - lo) / 2;
            if (daysNeeded(mid) <= (long long)days) { ans = mid; hi = mid - 1; }
            else lo = mid + 1;
        }
        return (int)ans;
    }
};

