class Solution {
public:
    int findPages(vector<int> &nums, int m)  {
        int n = nums.size();
        if (m > n) return -1;
        long long low = 0, high = 0;
        for (int i = 0; i < n; i++) {
            low = max(low, (long long)nums[i]);
            high += nums[i];
        }
        int ans = -1;
        while (low <= high) {
            long long mid = low + (high - low) / 2;

            int students = 1;
            long long pagesSum = 0;
            for (int i = 0; i < n; i++) {
                if (pagesSum + nums[i] <= mid) {
                    pagesSum += nums[i];
                } else {
                    students++;
                    pagesSum = nums[i];
                }
            }
            if (students <= m) {
                ans = (int)mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return ans;
    }
};

