class Solution {
public:

    ListNode* reverse(ListNode* head){
        ListNode* temp=head;
        ListNode* prev=NULL;

        while(temp!=NULL){
            ListNode* front=temp->next;
            temp->next=prev;
            prev=temp;
            temp=front;
        }
        return prev;
    }
    bool isPalindrome(ListNode* head) {
        if(head==NULL || head->next==NULL) return 1;

        ListNode* slow=head;
        ListNode* fast=head;

        while(fast->next!=NULL && fast->next->next!=NULL){
            slow=slow->next;
            fast=fast->next->next;
        }

        ListNode* newhead=reverse(slow->next);
        ListNode* first=head;
        ListNode* second=newhead;

        while(second!=NULL){
            if(first->val!=second->val) return false;
            first=first->next;
            second=second->next;
        }
        reverse(newhead);
        return true;
    }
};

