    ListNode* rotateRight(ListNode* head, int k) {
        if(head==NULL || k==0) return head;
        ListNode* temp=head;
        int len=1;

        while(temp->next!=NULL){
            temp=temp->next;
            len++;
        }

        if(k%len==0) return head;
        k=k%len;
        temp->next=head;

        ListNode* newnode=findnthnode(head,len-k);
        head=newnode->next;
        newnode->next=NULL;
        return head;
    }
};

