    }
};

distinct-subsequences.code:
class Solution{
  public: int distinctSubsequences(string s, string t){
        const int MOD = 1e9 + 7;
        int n = s.size(), m = t.size();


        vector<long long> dp(m + 1, 0);
        dp[0] = 1; 
        for (int i = 1; i <= n; i++) {

            for (int j = m; j >= 1; j--) {
                if (s[i - 1] == t[j - 1]) {
                    dp[j] = (dp[j] + dp[j - 1]) % MOD;
                }

            }
        }
        return (int)(dp[m] % MOD);
    }
};

