bool solve(int index, string& s, unordered_set<string>& dict) {
    if (index >= s.size()) {
        return true;
    }

    for (int i = index; i < s.size(); i++) {
        string temp = s.substr(index, i - index + 1);

        if (dict.find(temp) != dict.end() && solve(i + 1, s, dict)) {
            return true;
        }
    }

    return false;
}

