implement-min-stack.code:
class MinStack {
private:
    stack<long long> st;
    int mini;
public:
    MinStack() {
        mini = -1;
    }

    void push(int val) {
        if (st.empty()) {
            st.push(0);
            mini = val;
        } else {
            st.push((long long)val - mini);
            mini = min(val, mini);
        }
    }

    void pop() {
        if (st.top() < 0)
            mini = mini - st.top();
        st.pop();
    }

    int top() {
        int ans = -1;
        if (st.top() < 0)
            ans = mini;
        else
            ans = mini + st.top();
        return ans;
    }

    int getMin() {
        return mini;
    }
};

infix-to-postfix-conversion.code:
#include<bits/stdc++.h>
int priority(char c){
	if(c == '^') return 3;
	if(c == '*' || c == '/') return 2;
	if(c == '+' || c == '-') return 1;
	return -1;
}





string infixToPostfix(string exp){
	int n = exp.size(), i = 0;
	stack<char>st;
	string ans = "";

	while(i<n){
		if((exp[i] >= 'A' && exp[i] <= 'Z') || (exp[i] >= 'a' && exp[i] <= 'z') || (exp[i] >= '0' && exp[i] <= '9'))
		ans += exp[i];
		else if(exp[i] == '(') st.push(exp[i]);
		else if(exp[i] == ')'){

			while(!st.empty() && st.top() != '('){
				ans += st.top();
				st.pop();
			}
			st.pop();
		}
		else{
			int temp=priority(exp[i]);
			while(!st.empty() && temp <= priority(st.top())){
				ans += st.top();
				st.pop();
			}
			st.push(exp[i]);
		}
		i++;
	}

	while(!st.empty()){
		ans += st.top();
		st.pop();
	}
	return ans;
}

