minimum-window-substring-.code:
class Solution {
public:
    string minWindow(string s, string t) {
        if (t.empty() || s.size() < t.size()) return "";
        vector<int> need(128, 0);
        for (char c : t) need[(unsigned char)c]++;
        int required = (int)t.size();
        int left = 0, minLen = INT_MAX, minStart = 0;
        for (int right = 0; right < (int)s.size(); right++) {
            if (need[(unsigned char)s[right]] > 0) required--;
            need[(unsigned char)s[right]]--;
            while (required == 0) {
                if (right - left + 1 < minLen) {
                    minLen = right - left + 1;
                    minStart = left;
                }
                need[(unsigned char)s[left]]++;
                if (need[(unsigned char)s[left]] > 0) required++;
                left++;
            }
        }
        return minLen == INT_MAX ? "" : s.substr(minStart, minLen);
    }
};

implement-min-heap.code:
class minHeap {
public:
    vector<int> pq;


    void heapify(int node) {
        int leftChild = (2 * node) + 1;
        int rightChild = (2 * node) + 2;
        int smallest = node;

        if (leftChild < pq.size() && pq[leftChild] < pq[smallest])
            smallest = leftChild;

        if (rightChild < pq.size() && pq[rightChild] < pq[smallest])
            smallest = rightChild;

        if (smallest != node) {
            swap(pq[node], pq[smallest]);
            heapify(smallest);
        }
    }

    void bottomUpHeapify(int node) {
        int parent = (node - 1) / 2;
        if (parent >= 0 && pq[parent] > pq[node]) {
            swap(pq[parent], pq[node]);
            bottomUpHeapify(parent);
        }
    }


    void insert(int val) {
        pq.push_back(val);
        bottomUpHeapify(pq.size() - 1);
    }


    void removeMin() {
        pq[0] = pq.back();
        pq.pop_back();
        heapify(0);
    }


    int minElement() {
        return (pq.empty()) ? -1 : pq[0];
    }
};

