    }
    stack<TreeNode*> st;
    TreeNode* curr = root;
    pushLeft(curr, st);
    vector<int> ans;
    while (!st.empty()) {
        curr = st.top();
        st.pop();
        ans.push_back(curr->val);
        curr = curr->right;
        if (curr) {
            pushLeft(curr, st);
        }
    }
    return ans;
}

