zig-zag-or-spiral-traversal.code:
class Solution {
public:
    vector<vector<int>> zigzagLevelOrder(TreeNode* root) {
        vector<vector<int>>ans;
        if(root==NULL) return ans;
        queue<TreeNode*>q;
        q.push(root);
        bool f=1;

        while(!q.empty()){
            int size=q.size();
            vector<int>temp(size);
            for(int i=0;i<size;i++){
                TreeNode* node=q.front();
                q.pop();

                int ind=f?i:size-1-i;
                temp[ind]=node->val;
                if(node->left){
                    q.push(node->left);
                }
                if(node->right){
                    q.push(node->right);
                }
            }
            f=!f;
            ans.push_back(temp);
        }
        return ans;
    }
};

