two-sum-in-bst.code:
stack<TreeNode*> stl;
stack<TreeNode*> str;

void pushLeft(TreeNode* root) {
    while (root) {
        stl.push(root);
        root = root->left;
    }
}

void pushRight(TreeNode* root) {
    while (root) {
        str.push(root);
        root = root->right;
    }
}

int next() {
    if (stl.empty()) return 1e9;
    TreeNode* ans = stl.top();
    stl.pop();
    if (ans->right) {
        pushLeft(ans->right);
    }
    return ans->val;
}

int before() {
    if (str.empty()) return 1e9;
    TreeNode* ans = str.top();
    str.pop();
    if (ans->left) {
        pushRight(ans->left);
    }
    return ans->val;
}

bool findTarget(TreeNode* root, int k) {
    pushLeft(root);
    pushRight(root);

    int l = next();
    int r = before();
    while (l < r) {
        if (l == 1e9 || r == 1e9) return false;
        if (l + r == k) return true;
        else if (l + r < k) l = next();
        else r = before();
    }

    return false;
}

