class Solution{
public:
    int numberOfEnclaves(vector<vector<int>> &grid) {
        int n = grid.size();
        if (n == 0) return 0;
        int m = grid[0].size();
        vector<vector<bool>> vis(n, vector<bool>(m, false));
        queue<pair<int,int>> q;

        for (int j = 0; j < m; j++) {
            if (grid[0][j] == 1 && !vis[0][j]) { vis[0][j] = true; q.push({0, j}); }
            if (grid[n-1][j] == 1 && !vis[n-1][j]) { vis[n-1][j] = true; q.push({n-1, j}); }
        }
        for (int i = 0; i < n; i++) {
            if (grid[i][0] == 1 && !vis[i][0]) { vis[i][0] = true; q.push({i, 0}); }
            if (grid[i][m-1] == 1 && !vis[i][m-1]) { vis[i][m-1] = true; q.push({i, m-1}); }
        }
        int dr[] = {-1, 0, 1, 0};
        int dc[] = {0, 1, 0, -1};
        while (!q.empty()) {
            auto [r, c] = q.front(); q.pop();
            for (int d = 0; d < 4; d++) {
                int nr = r + dr[d], nc = c + dc[d];
                if (nr >= 0 && nr < n && nc >= 0 && nc < m && !vis[nr][nc] && grid[nr][nc] == 1) {
                    vis[nr][nc] = true;
                    q.push({nr, nc});
                }
            }
        }
        int ans = 0;
        for (int i = 0; i < n; i++)
            for (int j = 0; j < m; j++)
                if (grid[i][j] == 1 && !vis[i][j]) ans++;
        return ans;
    }
};

