typedef pair<int, pair<int, int>> tri;

int minimumEffortPath(vector<vector<int>>& heights) {
    int n = heights.size(), m = heights[0].size();
    vector<vector<int>> dis(n, vector<int>(m, 1e9));

    priority_queue<tri, vector<tri>, greater<tri>> pq;
    dis[0][0] = 0;
    pq.push({0, {0, 0}});

    vector<int> dr = {0, 0, 1, -1};
    vector<int> dc = {1, -1, 0, 0};

    int ans = INT_MIN;
    while (!pq.empty()) {
        tri t = pq.top();
        pq.pop();
        int x = t.second.first, y = t.second.second;
        ans = max(ans, t.first);
        if (x == n - 1 && y == m - 1) return ans;
        for (int i = 0; i < 4; i++) {
            int nx = x + dr[i], ny = y + dc[i];
            if (nx >= 0 && nx < n && ny >= 0 && ny < m && (dis[nx][ny] > abs(heights[x][y] - heights[nx][ny]))) {
                dis[nx][ny] = abs(heights[x][y] - heights[nx][ny]);
                pq.push({dis[nx][ny], {nx, ny}});
            }
        }
    }
    return -1; 
}

cheapest-flight-within-k-stops.code:
int findCheapestPrice(int n, vector<vector<int>>& flights, int src, int dst, int k) {
    vector<vector<pair<int, int>>> adj(n);
    for (auto flight : flights) {
        adj[flight[0]].push_back({flight[1], flight[2]});
    }

    queue<pair<int, int>> q;
    q.push({src, 0});

    vector<int> dis(n, 1e9);

    int stops = 0;
    while (!q.empty() && stops <= k) {
        int size = q.size();
        while (size--) {
            auto [u, uwt] = q.front();
            q.pop();
            for (auto& [v, vwt] : adj[u]) {
                if (vwt + uwt < dis[v]) {
                    dis[v] = uwt + vwt;
                    q.push({v, dis[v]});
                }
            }
        }
        stops++;
    }
    if (dis[dst] == 1e9)
        return -1;
    return dis[dst];
}

