    for (auto time : times) {
        adj[time[0]].push_back({time[1], time[2]});
    }
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    vector<int> dis(n + 1, 1e9);
    dis[k] = 0;
    pq.push({0, k});
    while (!pq.empty()) {
        auto [uwt, u] = pq.top();
        pq.pop();
        for (auto [v, vwt] : adj[u]) {
            if (dis[v] > uwt + vwt) {
                dis[v] = uwt + vwt;
                pq.push({dis[v], v});
            }
        }
    }
    int ans = INT_MIN;
    for (int i = 1; i <= n; i++) {
        if (dis[i] == 1e9)
            return -1;
        ans = max(ans, dis[i]);
    }
    return ans;
}

