    int spanningTree(int V, vector<vector<int>>& edges) {

        int sum=0;
        vector<vector<pair<int,int>>>adj(V);

        for(auto it:edges){
            int u=it[0];
            int v=it[1];
            int w=it[2];

            adj[u].push_back({v,w});
            adj[v].push_back({u,w});
        }

        priority_queue<pair<int,int>,vector<pair<int,int>>,
        greater<pair<int,int>>>pq;

        vector<bool>vis(V,0);

        pq.push({0,0});

        while(!pq.empty()){
            int edgw=pq.top().first;
            int node=pq.top().second;
            pq.pop();

            if(vis[node]) continue;

            vis[node]=1;
            sum+=edgw;

            for(auto &[neighbour,weight]:adj[node]){
                if(!vis[neighbour]){
                    pq.push({weight,neighbour});
                }
            }
        }

        return sum;
    }
};

number-of-operations-to-make-network-con.code:
class DisjointSet {
    vector<int> parent, size;

public:
    DisjointSet(int n) {
        parent.resize(n);
        size.resize(n, 1);
        for (int i = 0; i < n; i++)
            parent[i] = i;
    }

    int findUPar(int node) {
        if (parent[node] == node)
            return node;
        return parent[node] = findUPar(parent[node]);
    }

    void unionBySize(int u, int v) {
        int uP = findUPar(u), vP = findUPar(v);
        int uPSize = size[uP], vPSize = size[vP];
        if (uPSize > vPSize) {
            parent[vP] = uP;
            size[uP] += vPSize;
        } else {
            parent[uP] = vP;
            size[vP] += uPSize;
        }
    }

    int disconnected(int n) {
        int cnt = 0;
        for (int i = 0; i < n; i++) {
            if (parent[i] == i)
                cnt++;
        }
        return cnt;
    }
};

int makeConnected(int n, vector<vector<int>>& connections) {
    if (n - 1 > connections.size())
        return -1;

    DisjointSet djs(n);
    for (auto c : connections) {
        int u = c[0], v = c[1];
        if (djs.findUPar(u) != djs.findUPar(v))
            djs.unionBySize(u, v);
    }

    int ans = djs.disconnected(n);
    return ans - 1;
}

