vector<vector<string>> accountsMerge(vector<vector<string>>& accounts) {
    unordered_map<string, vector<int>> emailToAccountIndex;
    int n = accounts.size();
    DisjointSet djs(n);

    for (int u = 0; u < n; u++) {
        for (int i = 1; i < accounts[u].size(); i++) {
            emailToAccountIndex[accounts[u][i]].push_back(u);
        }
    }

    for (auto [email, users] : emailToAccountIndex) {
        for (int i = 1; i < users.size(); i++) {
            if (djs.findUPar(users[i - 1]) != djs.findUPar(users[i]))
                djs.unionSize(users[i - 1], users[i]);
        }
    }

    set<string> userMail[n];
    for (int i = 0; i < n; i++) {
        for (int m = 1; m < accounts[i].size(); m++) {
            userMail[djs.findUPar(i)].insert(accounts[i][m]);
        }
    }

    vector<vector<string>> ans;
    for (int i = 0; i < n; i++) {
        if (userMail[i].empty()) continue;
        vector<string> temp;
        temp.push_back(accounts[i][0]);
        for (auto m : userMail[i])
            temp.push_back(m);
        ans.push_back(temp);
    }

    return ans;
}

number-of-islands-ii.code:
class DisjointSet {
    vector<int> parent, size;

public:
    DisjointSet(int n) {
        size.resize(n, 1);
        parent.resize(n);
        for (int i = 0; i < n; i++) parent[i] = i;
    }

    int findUPar(int node) {
        if (parent[node] == node) return node;
        return parent[node] = findUPar(parent[node]);
    }

    void unionSize(int u, int v) {
        int up = findUPar(u), vp = findUPar(v);
        int us = size[up], vs = size[vp];
        if (us > vs) {
            parent[vp] = up;
            size[up] += vs;
        } else {
            parent[up] = vp;
            size[vp] += us;
        }
    }
};

bool isLand(int x, int y, vector<vector<int>>& grid) {
    return (x >= 0 && x < grid.size() && y >= 0 && y < grid[0].size() && grid[x][y] == 1);
}

vector<int> numOfIslands(int n, int m, vector<vector<int>>& operators) {
    vector<int> ans;
    int islands = 0;
    DisjointSet djs(n * m);
    vector<vector<int>> grid(n, vector<int>(m, 0));

    vector<int> dr = { -1, 1, 0, 0 };
    vector<int> dc = { 0, 0, -1, 1 };

    for (auto op : operators) {
        int x = op[0], y = op[1];
        if (grid[x][y] != 1) {
            grid[x][y] = 1;
            islands++;
            int id = x * m + y;
            for (int i = 0; i < 4; i++) {
                int nx = x + dr[i], ny = y + dc[i];
                if (isLand(nx, ny, grid)) {
                    int nid = nx * m + ny;
                    if (djs.findUPar(id) != djs.findUPar(nid)) {
                        djs.unionSize(id, nid);
                        islands--;
                    }
                }
            }
        }
        ans.push_back(islands);
    }
    return ans;
}

making-a-large-island.code:
class Solution {
public:
    vector<int> parent, sz;
    int find(int x){ while(parent[x]!=x){ parent[x]=parent[parent[x]]; x=parent[x]; } return x; }
    void unite(int a, int b){ a=find(a); b=find(b); if(a==b) return; if(sz[a]<sz[b]) swap(a,b); parent[b]=a; sz[a]+=sz[b]; }
    int largestIsland(vector<vector<int>>& grid) {
        int n = grid.size();
        if(n==0) return 0;
        parent.resize(n*n); sz.assign(n*n,1);
        for(int i=0;i<n*n;i++) parent[i]=i;
        int dr[4]={-1,1,0,0}, dc[4]={0,0,-1,1};
        for(int i=0;i<n;i++) for(int j=0;j<n;j++){
            if(grid[i][j]==1){
                for(int d=0;d<4;d++){
                    int ni=i+dr[d], nj=j+dc[d];
                    if(ni>=0&&ni<n&&nj>=0&&nj<n&&grid[ni][nj]==1){
                        unite(i*n+j, ni*n+nj);
                    }
                }
            }
        }
        int best=0;
        for(int i=0;i<n*n;i++) if(find(i)==i) best=max(best, sz[i]);
        for(int i=0;i<n;i++) for(int j=0;j<n;j++){
            if(grid[i][j]==0){
                set<int> roots;
                long long total=1;
                for(int d=0;d<4;d++){
                    int ni=i+dr[d], nj=j+dc[d];
                    if(ni>=0&&ni<n&&nj>=0&&nj<n&&grid[ni][nj]==1){
                        roots.insert(find(ni*n+nj));
                    }
                }
                for(int r:roots) total+=sz[r];
                best=max<long long>(best, total);
            }
        }
        return best;
    }
};

