class Solution {
public:
    int frogJump(vector<int>& heights) {
        int n = heights.size();
        if (n <= 1) return 0;
        vector<int> dp(n, 0);
        dp[0] = 0;
        dp[1] = abs(heights[1] - heights[0]);
        for (int i = 2; i < n; i++) {
            int oneStep = dp[i-1] + abs(heights[i] - heights[i-1]);
            int twoStep = dp[i-2] + abs(heights[i] - heights[i-2]);
            dp[i] = min(oneStep, twoStep);
        }
        return dp[n-1];
    }
};

house-robber.code:
int fmemo(int i, vector<int>& nums, vector<int>& dp) {
    if (i < 0)
        return 0;

    if (i == 0)
        return dp[i] = nums[i];

    if (dp[i] != -1)
        return dp[i];

    int take = nums[i] + fmemo(i - 2, nums, dp);
    int notake = fmemo(i - 1, nums, dp);
    return dp[i] = max(take, notake);
}


int ftab(int n, vector<int>& nums){
    vector<int> dp(n);
    dp[0] = nums[0];
    for(int i=1; i<n; i++){
        int take = nums[i];
        if(i-2 >= 0) take += dp[i-2];
        int notake = dp[i-1];
        dp[i] = max(take,notake);
    }
    return dp[n-1];
}


int fopt(int n, vector<int>& nums){
    int p1 = nums[0], p2 = 0, ans = p1;
    for(int i=1; i<n; i++){
        int take = nums[i];
        if(i-2 >= 0) take += p2;
        int notake = p1;
        ans = max(take,notake);
        p2 = p1; p1 = ans;
    }
    return ans;
}


int rob(vector<int>& nums) {
    int n = nums.size();
    vector<int> dp(n, -1);
    return fmemo(n - 1, nums, dp);
}

