class Solution {
public:
    int minFallingPathSum(vector<vector<int>>& matrix) {
        int m = matrix.size();
        int n = matrix[0].size();
        vector<long long> prev(n);
        for (int j = 0; j < n; j++) prev[j] = matrix[0][j];
        for (int i = 1; i < m; i++) {
            vector<long long> cur(n);
            for (int j = 0; j < n; j++) {
                long long best = prev[j];
                if (j - 1 >= 0) best = min(best, prev[j - 1]);
                if (j + 1 < n) best = min(best, prev[j + 1]);
                cur[j] = (long long)matrix[i][j] + best;
            }
            prev = cur;
        }
        long long ans = LLONG_MAX / 4;
        for (int j = 0; j < n; j++) ans = min(ans, prev[j]);
        return (int)ans;
    }
};

