            for (int prev = 0; prev < i; prev++) {
                if (arr[prev] < arr[i] && dp[i] < dp[prev] + 1) {
                    dp[i] = dp[prev] + 1;
                    prevmap[i] = prev;
                }
            }
        }
        int idx = (int)(max_element(dp.begin(), dp.end()) - dp.begin());
        vector<int> lis;
        int i = idx;
        while (i >= 0) {
            lis.push_back(arr[i]);
            i = prevmap[i];
        }
        reverse(lis.begin(), lis.end());
        return lis;
    }
};

