class Solution {
    public:
        int maxCoins(vector<int>& nums){
            int n = nums.size();
            vector<int> a(n + 2);
            a[0] = 1;
            a[n + 1] = 1;
            for (int i = 0; i < n; i++) a[i + 1] = nums[i];

            vector<vector<long long>> dp(n + 2, vector<long long>(n + 2, 0));
            for (int len = 2; len <= n + 1; len++) {
                for (int i = 0; i + len <= n + 1; i++) {
                    int j = i + len;
                    long long best = 0;
                    for (int k = i + 1; k < j; k++) {
                        long long coins = (long long)a[i] * a[k] * a[j] + dp[i][k] + dp[k][j];
                        best = max(best, coins);
                    }
                    dp[i][j] = best;
                }
            }
            return (int)dp[0][n + 1];
        }
};

palindrome-partitioning-ii-.code:
class Solution {
	public:
    	int minCut(string s){
            int n = s.size();
            if (n <= 1) return 0;
            vector<vector<bool>> isPal(n, vector<bool>(n, false));
            for (int i = 0; i < n; i++) isPal[i][i] = true;
            for (int len = 2; len <= n; len++) {
                for (int i = 0; i + len - 1 < n; i++) {
                    int j = i + len - 1;
                    if (s[i] == s[j]) {
                        if (len == 2) isPal[i][j] = true;
                        else isPal[i][j] = isPal[i+1][j-1];
                    }
                }
            }
            vector<int> dp(n+1, 0);
            dp[n] = -1;
            for (int i = n-1; i >= 0; i--) {
                int best = INT_MAX;
                for (int j = i; j < n; j++) {
                    if (isPal[i][j]) {
                        int cost = 1 + dp[j+1];
                        best = min(best, cost);
                    }
                }
                dp[i] = best;
            }
            return dp[0];
	    }
};

