        for (int i = 1; i <= n; i++) {
            long long maxVal = 0;
            long long best = LLONG_MIN;
            for (int len = 1; len <= k && len <= i; len++) {
                int idx = i - len; 
                maxVal = max(maxVal, (long long)arr[idx]);
                long long cand = dp[idx] + maxVal * (long long)len;
                best = max(best, cand);
            }
            dp[i] = best;
        }
        return (int)dp[n];
    }
};

longest-word-with-all-prefixes.code:
class Solution {
public:
    string completeString(vector<string>& nums) {
        struct TrieNode {
            TrieNode* children[26];
            bool end;
            TrieNode() {
                end = false;
                for (int i = 0; i < 26; i++) children[i] = nullptr;
            }
        };
        TrieNode* root = new TrieNode();

        for (auto& word : nums) {
            TrieNode* curr = root;
            for (char ch : word) {
                int key = ch - 'a';
                if (curr->children[key] == nullptr)
                    curr->children[key] = new TrieNode();
                curr = curr->children[key];
            }
            curr->end = true;
        }

        auto isValid = [&](const string& word) -> bool {
            TrieNode* curr = root;
            for (char ch : word) {
                int key = ch - 'a';
                if (curr->children[key] == nullptr || curr->children[key]->end == false)
                    return false;
                curr = curr->children[key];
            }
            return true;
        };
        string ans = "";
        bool found = false;
        for (auto& word : nums) {
            if (isValid(word)) {
                if (!found) { ans = word; found = true; }
                else if (word.size() > ans.size()) ans = word;
                else if (word.size() == ans.size() && word < ans) ans = word;
            }
        }
        if (!found) return "None";
        return ans;
    }
};

