            int lo = 0, hi = n - 1;
            while (lo <= hi) {
                int mid = lo + (hi - lo) / 2;
                if (nums[mid] <= x) {
                    floorVal = nums[mid];
                    lo = mid + 1;
                } else {
                    hi = mid - 1;
