class Solution {
public:
    int myAtoi(string input) {
        int n = (int)input.size();
        int i = 0;

        while (i < n && input[i] == ' ') i++;
        if (i == n) return 0;
        int sign = 1;
        if (input[i] == '+' || input[i] == '-') {
            if (input[i] == '-') sign = -1;
            i++;
        }
        long long ans = 0;
        while (i < n && input[i] >= '0' && input[i] <= '9') {
            ans = ans * 10 + (input[i] - '0');
            if (sign == 1 && ans > 2147483647LL) return 2147483647;
            if (sign == -1 && -ans < -2147483648LL) return -2147483648;
            i++;
        }
        ans = sign * ans;
        if (ans > 2147483647LL) return 2147483647;
        if (ans < -2147483648LL) return -2147483648;
        return (int)ans;
    }
};

frog-jump-with-k-distances.code:
class Solution {
public:
    int frogJump(vector<int>& heights, int k) {
        int n = heights.size();
        vector<long long> dp(n, 0);
        dp[0] = 0;
        for (int i = 1; i < n; i++) {
            long long best = LLONG_MAX;
            for (int j = 1; j <= k; j++) {
                if (i - j >= 0) {
                    long long cost = dp[i - j] + abs(heights[i] - heights[i - j]);
                    best = min(best, cost);
                }
            }
            dp[i] = best;
        }
        return (int)dp[n - 1];
    }
};

