rabin-karp-algorithm.code:
class Solution{
    public:
        vector <int> search(string pat, string txt) {
            vector<int> result;
            int n = txt.size();
            int m = pat.size();
            if (m == 0 || m > n) return result;

            const long long MOD = 1000000007LL;
            const long long BASE = 256LL;


            long long h = 1;
            for (int i = 0; i < m - 1; i++) {
                h = (h * BASE) % MOD;
            }

            long long patHash = 0, txtHash = 0;
            for (int i = 0; i < m; i++) {
                patHash = (patHash * BASE + (unsigned char)pat[i]) % MOD;
                txtHash = (txtHash * BASE + (unsigned char)txt[i]) % MOD;
            }

            for (int i = 0; i <= n - m; i++) {
                if (patHash == txtHash) {

                    bool match = true;
                    for (int j = 0; j < m; j++) {
                        if (txt[i + j] != pat[j]) { match = false; break; }
                    }
                    if (match) result.push_back(i);
                }
                if (i < n - m) {
                    txtHash = (txtHash - ((unsigned char)txt[i] * h) % MOD + MOD) % MOD;
                    txtHash = (txtHash * BASE + (unsigned char)txt[i + m]) % MOD;
                }
            }
            return result;
        }
};

count-all-subsequences-with-sum-k.code:
class Solution{
    public:    	
    int countSubsequenceWithTargetSum(vector<int>& nums, int k){
        int n = nums.size();

        vector<vector<long long>> dp(n+1, vector<long long>(k+1, 0));
        dp[0][0] = 1; 
        for(int i = 1; i <= n; i++){
            for(int t = 0; t <= k; t++){
                long long notTake = dp[i-1][t];
                long long take = 0;
                if(nums[i-1] <= t) take = dp[i-1][t - nums[i-1]];
                dp[i][t] = take + notTake;
            }
        }

        return (int)dp[n][k];
    }
};

edit-distance.code:
class Solution {
  public:
    int editDistance(string start, string target) {
        int n = start.size(), m = target.size();
        vector<int> prev(m + 1, 0), cur(m + 1, 0);
        for (int j = 0; j <= m; j++) prev[j] = j;
        for (int i = 1; i <= n; i++) {
            cur[0] = i;
            for (int j = 1; j <= m; j++) {
                if (start[i - 1] == target[j - 1]) {
                    cur[j] = prev[j - 1];
                } else {
                    cur[j] = 1 + min({prev[j - 1], prev[j], cur[j - 1]});
                }
            }
            prev = cur;
        }
        return prev[m];
    }
};

