check-if-the-number-if-armstrong.code:
class Solution {
public:
    bool isArmstrong(int n) {
        long long original = n;
        int digits = 0;
        long long temp = n;
        if (temp == 0) {
            digits = 1;
        } else {
            while (temp > 0) {
                digits++;
                temp /= 10;
            }
        }
        long long sum = 0;
        temp = n;
        if (temp == 0) {
            sum = 0;
        } else {
            while (temp > 0) {
                long long d = temp % 10;
                long long p = 1;
                for (int i = 0; i < digits; i++) p *= d;
                sum += p;
                temp /= 10;
            }
        }
        return sum == original;
    }
};

