maximum-rectangles.code:
class Solution
{
public:
    int largestRectangleArea(vector<int> &heights){
        int n = heights.size();
        stack<int> st;
        int maxArea = 0;
        for(int i = 0; i <= n; i++){
            int cur = (i == n) ? 0 : heights[i];
            while(!st.empty() && heights[st.top()] >= cur){
                int height = heights[st.top()];
                st.pop();
                int width = st.empty() ? i : (i - st.top() - 1);
                maxArea = max(maxArea, height * width);
            }
            st.push(i);
        }
        return maxArea;
    }
    int maximalAreaOfSubMatrixOfAll1(vector<vector<int>> &matrix){
        if(matrix.empty() || matrix[0].empty()) return 0;
        int m = matrix.size();
        int n = matrix[0].size();
        vector<int> heights(n, 0);
        int maxArea = 0;
        for(int i = 0; i < m; i++){
            for(int j = 0; j < n; j++){
                if(matrix[i][j] == 1) heights[j] += 1;
                else heights[j] = 0;
            }
            maxArea = max(maxArea, largestRectangleArea(heights));
        }
        return maxArea;
    }
};

kmp-algorithm-or-lps-array.code:
class Solution{
    public:
        vector <int> search(string pat, string txt){
            vector<int> result;
            int n = (int)txt.size(), m = (int)pat.size();
            if (m == 0 || m > n) return result;


            vector<int> lps(m, 0);
            for (int i = 1; i < m; i++) {
                int j = lps[i - 1];
                while (j > 0 && pat[i] != pat[j]) {
                    j = lps[j - 1];
                }
                if (pat[i] == pat[j]) {
                    j++;
                }
                lps[i] = j;
            }


            int j = 0; 
            for (int i = 0; i < n; i++) {
                while (j > 0 && txt[i] != pat[j]) {
                    j = lps[j - 1];
                }
                if (txt[i] == pat[j]) {
                    j++;
                }
                if (j == m) {
                    result.push_back(i - m + 1);
                    j = lps[j - 1]; 
                }
            }
            return result;
        }
};

best-time-to-buy-and-sell-stock-iv.code:
class Solution{
public:
    int stockBuySell(vector<int> arr, int n, int k){


        vector<vector<int>> ahead(k+1, vector<int>(2, 0));
        vector<vector<int>> cur(k+1, vector<int>(2, 0));
        for(int ind = n-1; ind >= 0; ind--){
            for(int cap = 1; cap <= k; cap++){
                for(int buy = 0; buy <= 1; buy++){
                    int profit;
                    if(buy == 0){ 
                        profit = max(-arr[ind] + ahead[cap][1], ahead[cap][0]);
                    } else { 
                        profit = max(arr[ind] + ahead[cap-1][0], ahead[cap][1]);
                    }
                    cur[cap][buy] = profit;
                }
            }
            ahead = cur;
        }
        return ahead[k][0];
    }
};
